import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/launch-targets.DIrU2w_6.js";const s=JSON.parse(`{"title":"Запуск гри в VS Code","description":"Дізнайтеся, як запустити екземпляр Minecraft із Visual Studio Code.","frontmatter":{"title":"Запуск гри в VS Code","description":"Дізнайтеся, як запустити екземпляр Minecraft із Visual Studio Code.","authors":["dicedpixels"],"prev":{"text":"Відкриття проєкту у VS Code","link":"./opening-a-project"},"next":{"text":"Генерація джерел у VS Code","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/vscode/launching-the-game.md","filePath":"translated/uk_ua/develop/getting-started/vscode/launching-the-game.md","lastUpdated":1774518827000}`);var c={name:`uk_ua/develop/getting-started/vscode/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Запуск гри в VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Запуск гри в VS Code”">​</a></h1><p>Інструментарій Fabric інтегрується з Visual Studio Code, щоб забезпечити зручний спосіб запуску екземпляра гри для тестування та налагодження вашого мода.</p><h2 id="generating-launch-targets" tabindex="-1">Генерація цілей запуску <a class="header-anchor" href="#generating-launch-targets" aria-label="Permalink to “Генерація цілей запуску”">​</a></h2><p>Щоб запустити гру з увімкненою підтримкою налагодження, вам потрібно буде створити цілі запуску, запустивши завдання Gradle <code>vscode</code>.</p><p>Це можна зробити з Gradle View у Visual Studio Code: відкрийте його та перейдіть до завдання <code>vscode</code> у <strong>Завдання</strong> &gt; <strong><code>ide</code></strong>. Двічі натисніть або скористайтеся кнопкою <strong>Виконати завдання</strong>, щоб виконати завдання.</p><p><img src="/assets/develop/getting-started/vscode/gradle-vscode.png" alt="Завдання vscode у Gradle View" loading="lazy"></p><p>Крім того, ви можете використовувати термінал безпосередньо: відкрийте новий термінал через <strong>Термінал</strong> &gt; <strong>Новий термінал</strong> і запустіть:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vscode</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vscode/terminal-vscode.png" alt="Завдання vscode в терміналіl" loading="lazy"></p><h3 id="using-launch-targets" tabindex="-1">Використання цілей запуску <a class="header-anchor" href="#using-launch-targets" aria-label="Permalink to “Використання цілей запуску”">​</a></h3><p>Після генерації цілей запуску ви можете використовувати їх, відкривши вікно <strong>Run and Debug</strong>, вибравши потрібну ціль і натиснувши кнопку <strong>Start Debugging</strong> (<kbd>F5</kbd>).</p><p><img src="/assets/develop/getting-started/vscode/launch-targets.png" alt="Цілі запуску" loading="lazy"></p>`,12)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};